import{_ as e,o as a,c as r,ae as d}from"./chunks/framework.Co1PSFSm.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"ChatDev 2.0","text":"DevAll 文档站","tagline":"零代码多智能体编排平台 — 用 YAML 定义工作流，用可视化界面运行","actions":[{"theme":"brand","text":"快速入门","link":"/zh/web-ui"},{"theme":"alt","text":"工作流编排","link":"/zh/workflow"}]},"features":[{"title":"零代码编排","details":"只需编写 YAML 配置文件，即可定义复杂的多智能体工作流。无需编码即可实现自动化流程。"},{"title":"多节点类型","details":"支持 Agent、Python、Human、Subgraph、Literal、Loop Counter 等多种节点类型。"},{"title":"动态并行","details":"支持 Map/Tree 模式的动态并行执行，可将任务自动拆分并行处理并归约结果。"},{"title":"循环图支持","details":"支持带环路的工作流图，使用 Tarjan 算法检测强连通分量，实现递归式环路执行。"},{"title":"多模型支持","details":"统一 Provider 抽象层，支持 OpenAI、Gemini、MiniMax、GLM 等多种 LLM 后端。"},{"title":"可视化界面","details":"Web UI 提供工作流可视化编辑器、实时执行监控、附件管理和日志查看功能。"}]},"headers":[],"relativePath":"zh/index.md","filePath":"zh/index.md"}'),l={name:"zh/index.md"};function i(h,t,o,n,s,u){return a(),r("div",null,[...t[0]||(t[0]=[d('<h2 id="产品定位" tabindex="-1">产品定位 <a class="header-anchor" href="#产品定位" aria-label="Permalink to &quot;产品定位&quot;">​</a></h2><p>ChatDev 2.0 (DevAll) 是一款<strong>零代码多智能体编排平台</strong>，通过 YAML 配置驱动复杂的多智能体协作流程。</p><p><strong>适用场景</strong>：</p><ul><li>数据可视化与报告生成</li><li>3D 内容创作</li><li>深度研究与信息聚合</li><li>软件开发自动化</li><li>任何需要多步骤、多角色协作的任务</li></ul><p><strong>与 ChatDev 1.0 的区别</strong>：</p><ul><li>ChatDev 1.0 是&quot;虚拟软件公司&quot;，通过角色（CEO、CTO、程序员）协作开发软件</li><li>ChatDev 2.0 是通用编排平台，通过 YAML 定义任意工作流，不限于软件开发</li></ul><h2 id="技术架构" tabindex="-1">技术架构 <a class="header-anchor" href="#技术架构" aria-label="Permalink to &quot;技术架构&quot;">​</a></h2><table tabindex="0"><thead><tr><th>组件</th><th>技术</th></tr></thead><tbody><tr><td>后端</td><td>Python + FastAPI + WebSocket</td></tr><tr><td>前端</td><td>Vue 3 + VueFlow + TypeScript</td></tr><tr><td>工作流引擎</td><td>DAG/循环图调度 + Tarjan SCC</td></tr><tr><td>运行环境</td><td>Docker / 本地 Python</td></tr><tr><td>部署</td><td>Docker Compose / GitHub Pages (文档)</td></tr></tbody></table><h2 id="快速导航" tabindex="-1">快速导航 <a class="header-anchor" href="#快速导航" aria-label="Permalink to &quot;快速导航&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文档</th><th>内容</th></tr></thead><tbody><tr><td><a href="/zh/web-ui.html">Web UI 快速入门</a></td><td>前端界面操作、启动工作流、人工审阅</td></tr><tr><td><a href="/zh/workflow.html">工作流编排</a></td><td>YAML 结构、节点类型、Provider 配置</td></tr><tr><td><a href="/zh/execution.html">图执行逻辑</a></td><td>DAG 执行、Tarjan 环路检测、超级节点</td></tr><tr><td><a href="/zh/dynamic.html">动态执行</a></td><td>Map/Tree 模式、并行处理、层级归约</td></tr><tr><td><a href="/zh/modules.html">模块参考</a></td><td>Memory、Thinking、Tooling 模块</td></tr><tr><td><a href="/zh/nodes.html">节点参考</a></td><td>Agent、Python、Human、Subgraph 等</td></tr></tbody></table><h2 id="外部链接" tabindex="-1">外部链接 <a class="header-anchor" href="#外部链接" aria-label="Permalink to &quot;外部链接&quot;">​</a></h2><ul><li><a href="https://github.com/OpenBMB/ChatDev" target="_blank" rel="noreferrer">GitHub 仓库</a></li><li><a href="https://github.com/OpenBMB/ChatDev/tree/chatdev1.0" target="_blank" rel="noreferrer">ChatDev 1.0 (Legacy)</a></li></ul>',12)])])}const m=e(l,[["render",i]]);export{c as __pageData,m as default};
